function solve(m, n, waitCost) {
    const dp = new Array(m).fill().map(() => new Array(n).fill().map(() => ({ odd: Infinity, even: Infinity })));
    dp[0][0].odd = (0 + 1) * (0 + 1); // initial cost at step 1 (odd)

    const queue = [[0, 0, true]]; // [i, j, isOddStep]

    while (queue.length > 0) {
        const [i, j, isOdd] = queue.shift();
        const currentCost = isOdd ? dp[i][j].odd : dp[i][j].even;

        if (isOdd) {
            // Next step is even (wait)
            const newCost = currentCost + waitCost[i][j];
            if (newCost < dp[i][j].even) {
                dp[i][j].even = newCost;
                queue.push([i, j, false]);
            }
        } else {
            // Next step is odd (move)
            // Move right
            if (j + 1 < n) {
                const newI = i;
                const newJ = j + 1;
                const moveCost = (newI + 1) * (newJ + 1);
                const newCost = currentCost + moveCost;
                if (newCost < dp[newI][newJ].odd) {
                    dp[newI][newJ].odd = newCost;
                    queue.push([newI, newJ, true]);
                }
            }
            // Move down
            if (i + 1 < m) {
                const newI = i + 1;
                const newJ = j;
                const moveCost = (newI + 1) * (newJ + 1);
                const newCost = currentCost + moveCost;
                if (newCost < dp[newI][newJ].odd) {
                    dp[newI][newJ].odd = newCost;
                    queue.push([newI, newJ, true]);
                }
            }
        }
    }

    return Math.min(dp[m-1][n-1].odd, dp[m-1][n-1].even);
}

